import{_ as t,c as a,o as p,ag as r}from"./chunks/framework.ELrfyV9R.js";const u=JSON.parse('{"title":"vitepress 自动发布个人网站","description":"","frontmatter":{"title":"vitepress 自动发布个人网站","cover_image":"../Gemini_Generated_Image_9paxk69paxk69pax.png"},"headers":[],"relativePath":"ai/2026-03/2026-03-15-vitepress.md","filePath":"ai/2026-03/2026-03-15-vitepress.md","lastUpdated":1774480913000}'),s={name:"ai/2026-03/2026-03-15-vitepress.md"};function i(o,e,n,l,g,d){return p(),a("div",null,e[0]||(e[0]=[r('<p>站在2026年的视角，AI时代，我们还有必要创建我们的个人门户网站吗？我们还有必要自己写点东西留存在互联网上吗？未来互联网会死吗？</p><p>况且现在不论什么问题，我都愿意先问问AI了，看看它能给我什么答案? 我相信已经有很多很多人跟我一样了。那么你有没有想过一个问题: AI给我们的这些高质量答案，又是从哪里来的呢?</p><p>答案其实就是: 来自AI“能看见”的地方。</p><p>同时最近的315GEO数据投毒事件，某网上爆火，几乎所有人都能看到这个话题的内容。那么这里我顺便简单说一下GEO。</p><p>GEO（Generative Engine Optimization，也叫生成式引擎优化）是一种针对AI搜索引擎内容的优化策略。核心目标不是让你的网页排名靠前，而是让AI在回答用户问题时，<strong>直接引用你的内容、提及你的品牌。</strong></p><p>那我们应该怎么做呢？我可以在微信公众号、短视频、小红书、抖音、头条、知乎等等平台来构建自己的内容和品牌。而且完全可以做到全平台批量构建。 但是这些平台都有一个重大的弊端，我的内容或者我的账号，会在某个特定的早晨，因为一些各种各样的问题而意外面临某篇文章或视频的下架，甚至某个账号的永久封禁，从而导致我很多的内容资产消失。</p><p>所以当下我觉得AI时代，我的个人网站又必须排上日程了。它不再仅仅是给我记录笔记也好，构建内容和品牌也罢，学习当前最流行的AI前线技术也行。而更重要的一点，就是上面提及的让AI能更好的发现我。</p><p>我们的网站可能被某某云下架，但是我们的内容在本地，在云端、在github，通过简单整改后仍然可以再次上线，甚至部署在别人无法触手可及的地方，只要不违背大的原因，他甚至可以永远存在。</p><p>而针对我们的网站，我们可以给它架设robots.txt确保AI能爬取到我们的内容，也给网站部署上llms.txt，告诉AI我是谁，我的网站干什么的，有什么内容，内容列表又是哪些。</p><p>有关SEO和GEO的更多内容可以参考这篇文章</p><p><a href="https://x.com/YangGuangAI/status/2033522959407878621" target="_blank" rel="noreferrer">https://x.com/YangGuangAI/status/2033522959407878621</a></p><p>自媒体，独立开发者，现在流行的OPC，甚至越来越多的人，可能都在构建自己的个人独立网站。</p><p>说了那么多没用的，下面开始建造属于自己的避风港。</p><h2 id="项目整体搭建流程" tabindex="-1">项目整体搭建流程 <a class="header-anchor" href="#项目整体搭建流程" aria-label="Permalink to &quot;项目整体搭建流程&quot;">​</a></h2><p>我先说一下我这套方案整体的一个工作流程是怎么样的</p><p>![[Pasted image 20260321094909.png]]</p><ul><li>我在本地使用 <strong>Obsidian客户端</strong> 管理我的个人知识库，作为我的第二大脑</li><li>目前所有文章都用 <strong>Markdown</strong> 编写</li><li>Markdown 的目录结构按 <strong>VitePress</strong> 规范来组织</li><li>平常使用 <strong>Claude Code</strong> 对内容做整理加工</li><li>Claude Code 的处理过程可以拆给多个 <strong>Skills / SubAgent/ Agent Teams</strong></li><li>加工好的 Markdown 文件保存回本地仓库，图床也有多个方案</li><li>把改动提交到 <strong>GitHub</strong></li><li>提交完毕自动触发 Cloudflare 的 Git 集成流程，<strong>Cloudflare Pages</strong> 自动构建并发布</li><li>绑定域名后，页面即可对外访问</li></ul><p>下面正式开始</p><h2 id="_1、搭建本地环境" tabindex="-1">1、搭建本地环境 <a class="header-anchor" href="#_1、搭建本地环境" aria-label="Permalink to &quot;1、搭建本地环境&quot;">​</a></h2><p>前置条件其实就是安装nodejs、git、obdisian客户端，如果没有的话可以让AI帮忙安装一下也可以自己手动进行下载，如果你本地没有AI工具，可以先下载使用Codex或者OpenCode，这两个客户端工具不需要其他依赖安装就可以使用，还是非常方便的，然后再来安装其他搭建所需的就可以了。 nodejs版本最好最好用最新的。</p><p><strong>“帮我看看nodejs,git,obdisia客户端是否安装了，如果没安装帮我安装一下”</strong></p><p>![[Pasted image 20260320070923.png]]</p><p>箭头所示中间过程我已经省略了，这里默认工具都已经安装好了，，如果你没有安装，可以参考下面的链接根据需要进行逐一安装。</p><p>可以先了解一下Git有什么作用 <a href="https://x.com/aehyok/status/2015962566322008442" target="_blank" rel="noreferrer">https://x.com/aehyok/status/2015962566322008442</a></p><p>Obsidian安装 <a href="https://x.com/cheery9998/status/2023662846048170464" target="_blank" rel="noreferrer">https://x.com/cheery9998/status/2023662846048170464</a></p><p>给Obsidian装上Claude Code插件 <a href="https://x.com/alin_zone/status/2020818787134845234?s=20" target="_blank" rel="noreferrer">https://x.com/alin_zone/status/2020818787134845234?s=20</a></p><p>直接使用本地命令行Claude Code， 我觉得才是最有价值的工具，目前来说没有之一。 <a href="https://x.com/LawrenceW_Zen/status/2031924759634854248" target="_blank" rel="noreferrer">https://x.com/LawrenceW_Zen/status/2031924759634854248</a></p><p>当然了Claude Code配置确实有门槛，Codex或者Google Antigravity 也是不错的选择。 <a href="https://x.com/cheery9998/status/2030148892935999599" target="_blank" rel="noreferrer">https://x.com/cheery9998/status/2030148892935999599</a></p><p>这个准备的小章节还有一个重头戏就是markdown里的图应该怎么搞，这里推荐一种方案：Cloudflare R2 + PicList谁用谁觉得好用，还免费。 <a href="https://x.com/Lonely__MH/status/2034249327003230691" target="_blank" rel="noreferrer">https://x.com/Lonely__MH/status/2034249327003230691</a></p><p>准备完毕了开始创建项目吧。</p><h2 id="_2、安装vitepress准备项目代码" tabindex="-1">2、安装vitepress准备项目代码 <a class="header-anchor" href="#_2、安装vitepress准备项目代码" aria-label="Permalink to &quot;2、安装vitepress准备项目代码&quot;">​</a></h2><p>搭建项目前，先来简单看看VitePress用来干什么的。</p><p>它主要就是用来<strong>把 Markdown 文档变成一个可访问的网站</strong>的。所以我们完全可以不关注VitePress，我们只需要关注目录和Markdown文档就可以了，就跟直接在Obsidian 客户端下面打开一个文件夹一样，so easy! 同时他也有很方便的拓展性，这个简单提一嘴，后期有需要专门写一篇。</p><p>当然了其实还有很多其他类似的框架，我就不列举了，有兴趣可以多问问AI。</p><p><strong>在当前文件夹下给我使用vitepress给我创建一个代码仓库</strong></p><p>![[Pasted image 20260320071109.png]]</p><p>依赖安装完毕，可以叫他本地直接跑项目看效果了。</p><p><strong>&quot;你直接给我启动运行本项目&quot;</strong></p><p>![[Pasted image 20260320071316.png]]</p><p>看到访问地址基本就OK了，浏览器输入访问看效果。</p><p>![[Pasted image 20260315225949.png]]</p><h2 id="_3、将代码上传github" tabindex="-1">3、将代码上传github <a class="header-anchor" href="#_3、将代码上传github" aria-label="Permalink to &quot;3、将代码上传github&quot;">​</a></h2><p>我相信看到这里的人绝大部分人应该都知道它是全球最大的开源项目大本营。现在有太多跟AI相干的开源项目，都放在了这个github网站上。它不仅仅能放项目代码，而且文档文档、少量图片、教程等都可以，付费用户当然功能更多，咱就不展开了，知道能放代码，知道能跟Git结合使用管理代码的版本历史，暂时就够了。</p><p><strong>&quot;将项目上传到github&quot;</strong></p><p>![[Pasted image 20260316061033.png]]</p><p>告诉我还差github项目仓库信息，那么现在就需要到github官网上创建一个项目。</p><p>&quot;<a href="https://github.com/new" target="_blank" rel="noreferrer">https://github.com/new</a> 浏览器打开这个链接，直接创建项目&quot;</p><p>![[Pasted image 20260316063015.png]]</p><p>上面链接要先进行登录这里就不进行重点讲解了，主要就是箭头两个重点</p><ul><li>仓库名称，尽量用英文字母</li><li>choose visibility，我选择的public，意思就是开源，所有人都可以看到，另外一个private就是私有的，只有自己能看到。</li><li>剩下的你可以直接默认，也可以参考我的进行选择，然后点击右下角 Create repository。</li><li>仓库创建完毕就会直接跳转到当前仓库。</li></ul><p>![[Pasted image 20260316070834.png]]</p><p>如上图箭头所示 复制SSH链接， 继续跟AI聊天。</p><p>“ <a href="mailto:git@github.com" target="_blank" rel="noreferrer">git@github.com</a>:aehyok/vitepress-obsidian.git 这是我新创建的仓库，创建类型为public，请将当前仓库代码上传github”</p><p>![[Pasted image 20260317071023.png]]</p><p>好了，我们已经将本地代码上传到Github上了。</p><h2 id="_4、cloudflare上部署我们的项目代码" tabindex="-1">4、cloudflare上部署我们的项目代码 <a class="header-anchor" href="#_4、cloudflare上部署我们的项目代码" aria-label="Permalink to &quot;4、cloudflare上部署我们的项目代码&quot;">​</a></h2><p>cloudfare上功能实在太多，而在中文圈被誉为互联网的赛博菩萨大善人。提供了众多免费的功能。 尤其是部署个小站点，完全免费。接下来跟着我操作一下。</p><p><a href="https://cloudflare.com" target="_blank" rel="noreferrer">https://cloudflare.com</a> 打开网站，如果没有账号就进行注册登录，登录之后右上角语言切换简体中文，设置完毕首页如下所示。</p><p>![[Pasted image 20260317153943.png]]</p><p>点击开始[构建]，进入页面会看到下面 [pages] 点击 开始使用 ![[Pasted image 20260317173522.png]]</p><p>进入页面后点击 导入现有Git存储库 开始使用，如果没关联过需要登录github进行授权的</p><p>选择 Only select repositories-&gt; Select repositories=-&gt; 文本框输入 obsidian-&gt; 选中代码仓库-&gt;点击绿色的 Save-&gt;稍等片刻会返回到cloudflare网站。也就是关闭弹窗。</p><p>![[Pasted image 20260317155017.png]]</p><p>回到cloudflare网站，选择好刚刚设置的仓库，点击右下角开始设置就可以了。</p><p>![[Pasted image 20260317174611.png]]</p><p>点击下一步 框架预设：选择VitePress 构建命令： npm vitepress build 构建输出目录：docs/.vitepress/dist</p><p>![[Pasted image 20260317181016.png]]</p><p>![[Pasted image 20260317175259.png]]</p><p>好了，兄弟们，网站有了。直接进行点击，cloudflare给我们的免费域名</p><h2 id="_6、更新网站内容" tabindex="-1">6、更新网站内容 <a class="header-anchor" href="#_6、更新网站内容" aria-label="Permalink to &quot;6、更新网站内容&quot;">​</a></h2><p>直接用下面的提示词修改首页的title。</p><p>![[Pasted image 20260321063954.png]]</p><p>![[Pasted image 20260321064231.png]]</p>',73)]))}const c=t(s,[["render",i]]);export{u as __pageData,c as default};
